const ALEF='<img src="../letters/alef.png" alt="א" />',BET='<img src="../letters/bet.png" alt="ב" />',GIMEL='<img src="../letters/gimel.png" alt="ג" />',DALET='<img src="../letters/dalet.png" alt="ד" />',HE='<img src="../letters/he.png" alt="ה" />',VAV='<img src="../letters/vav.png" alt="ו" />',ZAYIN='<img src="../letters/zain.png" alt="ז" />',CHET='<img src="../letters/chet.png" alt="ח" />',TET='<img src="../letters/tet.png" alt="ט" />',YOD='<img src="../letters/yod.png" alt="י" />',KAF='<img src="../letters/kaf.png" alt="כ" />',LAMED='<img src="../letters/lamed.png" alt="ל" />',MEM='<img src="../letters/meim.png" alt="מ" />',NUN='<img src="../letters/nun.png" alt="נ" />',SAMECH='<img src="../letters/samech.png" alt="ס" />',AYIN='<img src="../letters/hain.png" alt="ע" />',PE='<img src="../letters/pai.png" alt="פ" />',TSADI='<img src="../letters/zadik.png" alt="צ" />',QOF='<img src="../letters/koff.png" alt="ק" />',RESH='<img src="../letters/riesh.png" alt="ר" />',SHIN1='<img src="../letters/shin.png" alt="ש" />',TAV='<img src="../letters/taff.png" alt="ת" />',signs={"א":ALEF,"ב":BET,"ג":GIMEL,"ד":DALET,"ה":HE,"ו":VAV,"ז":ZAYIN,"ח":CHET,"ט":TET,"י":YOD,"כ":KAF,"ל":LAMED,"מ":MEM,"נ":NUN,"ס":SAMECH,"ע":AYIN,"פ":PE,"צ":TSADI,"ק":QOF,"ר":RESH,"ש":SHIN1,"ת":TAV},letters=["א","ב","ג","ד","ה","ו","ז","ח","ט","י","כ","ל","מ","נ","ס","ע","פ","צ","ק","ר","ש","ת"];let queue=[],current=null,qIndex=0,scoreCorrect=0,scoreWrong=0,answered=!1;const total=letters.length;function shuffle(e){let t=[...e];for(let e=t.length-1;e>0;e--){const n=Math.floor(Math.random()*(e+1));[t[e],t[n]]=[t[n],t[e]]}return t}function startGame(){queue=shuffle(letters),qIndex=0,scoreCorrect=0,scoreWrong=0,document.getElementById("scoreCorrect").textContent=0,document.getElementById("scoreWrong").textContent=0,document.getElementById("endScreen").classList.remove("visible"),["questionCard","optionsGrid"].forEach(e=>document.getElementById(e).style.display=""),document.querySelector(".progress-bar-wrap").style.display="",document.getElementById("progressLabel").style.display="",document.querySelector(".score-strip").style.display="",loadQuestion()}function loadQuestion(){answered=!1,document.getElementById("nextBtn").classList.remove("visible");const e=document.getElementById("feedback");e.className="feedback hidden",e.textContent="",current=queue[qIndex],document.getElementById("hebrewLetter").textContent=current,document.getElementById("letterName").textContent=current;const t=Math.round(qIndex/total*100);document.getElementById("progressBar").style.width=t+"%",document.getElementById("progressLabel").textContent=`שאלה ${qIndex+1} מתוך ${total}`;const n=shuffle(letters.filter(e=>e!==current)).slice(0,3),s=shuffle([current,...n]),r=document.getElementById("optionsGrid");r.innerHTML="",["A","B","C","D"].forEach((e,t)=>{const n=document.createElement("button");n.className="option-btn",n.innerHTML=`<div class="opt-label">${e}</div>${signs[s[t]]}`,n.onclick=()=>handleAnswer(s[t]===current,n,s),r.appendChild(n)});const o=document.getElementById("questionCard");o.style.animation="none",setTimeout(()=>{o.style.animation=""},10)}function handleAnswer(e,t,n){if(answered)return;answered=!0;const s=document.querySelectorAll(".option-btn");s.forEach(e=>e.disabled=!0);const r=document.getElementById("feedback");e?(t.classList.add("correct"),scoreCorrect++,document.getElementById("scoreCorrect").textContent=scoreCorrect,r.className="feedback correct",r.textContent="✅ נכון! כל הכבוד!"):(t.classList.add("wrong"),scoreWrong++,document.getElementById("scoreWrong").textContent=scoreWrong,r.className="feedback wrong",r.textContent=`❌ לא נכון. הסימן הנכון של "${current}" מסומן בירוק`,s.forEach((e,t)=>{n[t]===current&&e.classList.add("correct")})),document.getElementById("nextBtn").classList.add("visible")}function nextQuestion(){qIndex++,qIndex>=total?showEnd():loadQuestion()}function showEnd(){["questionCard","optionsGrid"].forEach(e=>document.getElementById(e).style.display="none"),document.querySelector(".progress-bar-wrap").style.display="none",document.getElementById("progressLabel").style.display="none",document.querySelector(".score-strip").style.display="none",document.getElementById("nextBtn").classList.remove("visible"),document.getElementById("feedback").className="feedback hidden";const e=Math.round(scoreCorrect/total*100);document.getElementById("endScore").textContent=`${scoreCorrect}/${total}`;let t="";t=100===e?"🏆 מושלם! שלטת בכל האותיות!":e>=80?"🌟 מצוין! כמעט מושלם!":e>=60?"👍 יפה מאוד! תוכל לשפר עוד יותר":e>=40?"💪 טוב! כדאי לתרגל עוד קצת":"📚 המשך לתרגל – תשתפר!",document.getElementById("endMsg").textContent=t,document.getElementById("endScreen").classList.add("visible")}startGame();